import React from 'react';
import useDocumentSync from '../hooks/useDocumentSync';
import Cursor from './Cursor';

const TextEditor = () => {
  const {
    content,
    remoteCursor,
    textareaRef,
    handleContentChange,
    handleCursorChange
  } = useDocumentSync('');

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h2>Collaborative Text Editor</h2>
        <p>Open this page in two different browsers/windows to test real-time collaboration</p>
      </div>
      <div style={styles.editorContainer}>
        <textarea
          ref={textareaRef}
          value={content}
          onChange={handleContentChange}
          onSelect={handleCursorChange}
          onClick={handleCursorChange}
          onKeyUp={handleCursorChange}
          style={styles.textarea}
          placeholder="Start typing..."
        />
        <Cursor position={remoteCursor.position} textareaRef={textareaRef} />
      </div>
      <div style={styles.stats}>
        <div>Characters: {content.length}</div>
        <div>Words: {content.trim() ? content.trim().split(/\s+/).length : 0}</div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    height: '100vh',
    padding: '20px',
    boxSizing: 'border-box',
    fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif'
  },
  header: {
    marginBottom: '20px',
    textAlign: 'center'
  },
  editorContainer: {
    flex: 1,
    position: 'relative',
    border: '1px solid #ddd',
    borderRadius: '4px',
    overflow: 'hidden'
  },
  textarea: {
    width: '100%',
    height: '100%',
    padding: '20px',
    fontSize: '16px',
    lineHeight: '1.5',
    border: 'none',
    outline: 'none',
    resize: 'none',
    fontFamily: 'monospace',
    boxSizing: 'border-box'
  },
  stats: {
    marginTop: '10px',
    display: 'flex',
    gap: '20px',
    color: '#666',
    fontSize: '14px'
  }
};

export default TextEditor;