import { useState, useEffect, useRef, useCallback } from 'react';
import { documentRef, onValue, set, off } from '../firebase';
import debounce from 'lodash/debounce';

const useDocumentSync = (initialContent = '') => {
  const [content, setContent] = useState(initialContent);
  const [cursorPosition, setCursorPosition] = useState(0);
  const [selection, setSelection] = useState({ start: 0, end: 0 });
  const [remoteCursor, setRemoteCursor] = useState({ position: 0, selection: { start: 0, end: 0 } });
  const isRemoteUpdate = useRef(false);
  const textareaRef = useRef(null);

  // Load initial data from Firebase
  useEffect(() => {
    const unsubscribe = onValue(documentRef, (snapshot) => {
      const data = snapshot.val();
      if (data && data.content !== undefined) {
        isRemoteUpdate.current = true;
        setContent(data.content);
        setRemoteCursor({
          position: data.cursorPosition || 0,
          selection: data.selection || { start: 0, end: 0 }
        });
        
        // Restore cursor position after remote update
        if (textareaRef.current) {
          setTimeout(() => {
            textareaRef.current.selectionStart = data.cursorPosition || 0;
            textareaRef.current.selectionEnd = data.cursorPosition || 0;
          }, 0);
        }
      }
    });

    return () => {
      unsubscribe();
      off(documentRef);
    };
  }, []);

  // Debounced update to Firebase
  const updateFirebase = useCallback(
    debounce((newContent, cursorPos, sel) => {
      set(documentRef, {
        content: newContent,
        cursorPosition: cursorPos,
        selection: sel,
        timestamp: Date.now()
      });
    }, 100),
    [] // Empty dependency array is fine for debounced function
  );

  const handleContentChange = (e) => {
    const newContent = e.target.value;
    const cursorPos = e.target.selectionStart;
    const sel = {
      start: e.target.selectionStart,
      end: e.target.selectionEnd
    };

    setContent(newContent);
    setCursorPosition(cursorPos);
    setSelection(sel);

    if (!isRemoteUpdate.current) {
      updateFirebase(newContent, cursorPos, sel);
    } else {
      isRemoteUpdate.current = false;
    }
  };

  const handleCursorChange = (e) => {
    const cursorPos = e.target.selectionStart;
    const sel = {
      start: e.target.selectionStart,
      end: e.target.selectionEnd
    };
    
    setCursorPosition(cursorPos);
    setSelection(sel);
    
    if (!isRemoteUpdate.current) {
      updateFirebase(content, cursorPos, sel);
    }
  };

  return {
    content,
    setContent,
    cursorPosition,
    selection,
    remoteCursor,
    textareaRef,
    handleContentChange,
    handleCursorChange
  };
};

export default useDocumentSync;